    margin: 0;
    font-weight: 600;
    color: #333;
}

.product-price {
    font-size: 1.1rem;
    font-weight: 700;
    color: #2a7ae2;
    margin: 0;
}

.product-rating {
    color: #f5a623;
    font-size: 1rem;
    letter-spacing: 2px;
}

.badge-out-of-stock {
    display: inline-block;
    background: #e74c3c;
    color: #fff;
    padding: 0.2rem 0.5rem;
    border-radius: 4px;
    font-size: 0.75rem;
    font-weight: 600;
    align-self: flex-start;
}

.btn-add-to-cart {
    margin-top: auto;
    padding: 0.5rem 1rem;
    border: none;
    border-radius: 6px;
    background: #2a7ae2;
    color: #fff;
    font-weight: 600;
    cursor: pointer;
