    border-radius: 4px;
    font-size: 0.9rem;
    width: 100%;
    box-sizing: border-box;
}

.filter-actions {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    margin-top: 1rem;
}

.btn-apply {
    padding: 0.6rem 1rem;
    border: none;
    border-radius: 6px;
    background: #2a7ae2;
    color: #fff;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.2s;
}

.btn-apply:hover {
    background: #1a5bb5;
}

.btn-clear {
    padding: 0.6rem 1rem;
    border: 1px solid #ccc;
    border-radius: 6px;
    background: #fff;
    color: #555;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.2s;
}

.btn-clear:hover {
    background: #f0f0f0;
}

.catalog-toolbar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.75rem 1rem;
    background: #f8f9fa;
    border-radius: 8px;
    border: 1px solid #e0e0e0;
    margin-bottom: 1rem;
    flex-wrap: wrap;
    gap: 0.5rem;
}

.sort-control {
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.sort-control label {
    font-weight: 600;
    font-size: 0.9rem;
    color: #555;
}

.sort-control select {
    padding: 0.4rem 0.6rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 0.9rem;
    background: #fff;
}

.results-summary {
    font-size: 0.9rem;
    color: #666;
}

.pagination {
    display: flex;
    justify-content: center;
    align-items: center;
    gap: 0.4rem;
    margin-top: 1.5rem;
    flex-wrap: wrap;
}

.page-btn {
    padding: 0.5rem 0.9rem;
    border: 1px solid #ddd;
    border-radius: 6px;
    background: #fff;
    cursor: pointer;
    font-size: 0.9rem;
    transition: all 0.2s;
    color: #333;
}

.page-btn:hover:not(:disabled):not(.active) {
    background: #f0f0f0;
    border-color: #bbb;
}

.page-btn.active {
    background: #2a7ae2;
    color: #fff;
    border-color: #2a7ae2;
    font-weight: 600;
}

.page-btn:disabled {
    color: #bbb;
