{"file_text": "<nav class="pagination" aria-label="Product pagination">
    <button class="page-btn" disabled="@(CurrentPage <= 1)" @onclick="GoToPrevious">
        Previous
    </button>

    @for (int i = 1; i <= TotalPages; i++)
    {
        var pageNum = i;
        <button class="page-btn @(pageNum == CurrentPage ? "active" : "")"
                @onclick="@(() => GoToPage(pageNum))">
            @pageNum
        </button>
    }

    <button class="page-btn" disabled="@(CurrentPage >= TotalPages)" @onclick="GoToNext">
        Next
    </button>
</nav>

@code {
    [Parameter]
    public int CurrentPage { get; set; }

    [Parameter]
    public int TotalPages { get; set; }

    [Parameter]
    public EventCallback<int> OnPageChanged { get; set; }

    private async Task GoToPage(int page)
    {
        if (page != CurrentPage && page >= 1 && page <= TotalPages)
        {
            await OnPageChanged.InvokeAsync(page);
        }
    }

    private async Task GoToPrevious() => await GoToPage(CurrentPage - 1);
    private async Task GoToNext() => await GoToPage(CurrentPage + 1);
}
