arguments.file_text:
@page "/catalog"
@using sv_b527aaa2df084251babe940933470cd1.Services
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<div class="catalog-page">
    <aside class="catalog-sidebar">
        <CatalogFilters Categories="_categories"
                        OnFiltersApplied="HandleFiltersApplied" />
    </aside>

    <main class="catalog-main">
        @if (_isLoading)
        {
            <div class="catalog-status">
                <p>Loading products…</p>
            </div>
        }
        else if (_errorMessage is not null)
        {
            <div class="catalog-status catalog-error">
                <p>@_errorMessage</p>
                <button class="btn-retry" @onclick="LoadProductsAsync">Retry</button>
            </div>
        }
        else if (_result is null || _result.Items.Count == 0)
        {
            <div class="catalog-status">
                <p>No products found. Try adjusting your filters.</p>
            </div>
        }
        else
        {
            <CatalogToolbar SortBy="@_sortBy"
                            TotalCount="_result.TotalCount"
                            Page="_result.Page"
                            PageSize="_result.PageSize"
                            OnSortChanged="HandleSortChanged" />

            <div class="product-grid">
                @foreach (var product in _result.Items)
                {
                    <ProductCard Product="product"
                                 OnProductSelected="HandleProductSelected"
                                 OnAddToCart="HandleAddToCart" />
                }
            </div>

            @if (_totalPages > 1)
            {
                <CatalogPagination CurrentPage="_currentPage"
                                   TotalPages="_totalPages"
                                   OnPageChanged="HandlePageChanged" />
            }
        }
    </main>
</div>

@code {
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<string>? _categories;
    private PagedResult<Product>? _result;
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private const int PageSize = 12;
    private bool _isLoading;
    private string? _errorMessage;

    private int _totalPages => _result is null || _result.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)_result.TotalCount / _result.PageSize);

    protected override async Task OnInitializedAsync()
    {
        await LoadCategoriesAsync();
        await LoadProductsAsync();
    }

    private async Task LoadCategoriesAsync()
    {
        try
        {
            _categories = await ProductService.GetCategoriesAsync();
        }
        catch
        {
            _categories = new List<string>();
        }
    }

    private async Task LoadProductsAsync()
    {
        _isLoading = true;
        _errorMessage = null;
        StateHasChanged();

        try
        {
            _result = await ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to load products: {ex.Message}";
            _result = null;
        }
        finally
        {
            _isLoading = false;
        }
    }

    private async Task HandleFiltersApplied(ProductFilter filter)
    {
        _filter = filter;
        _currentPage = 1;
        await LoadProductsAsync();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _currentPage = 1;
        await LoadProductsAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await LoadProductsAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for cart functionality
        return Task.CompletedTask;
    }
}

.catalog-page {
    display: flex;
    gap: 1.5rem;
    max-width: 1400px;
    margin: 0 auto;
    padding: 1.5rem;
}

.catalog-sidebar {
    flex: 0 0 25%;
    min-width: 220px;
}

.catalog-main {
    flex: 1;
    min-width: 0;
}

.product-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(240px, 1fr));
    gap: 1.25rem;
}

.catalog-status {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 3rem 1rem;
    text-align: center;
    color: #666;
    font-size: 1rem;
}

.catalog-error {
    color: #c0392b;
}

.btn-retry {
    margin-top: 1rem;
    padding: 0.5rem 1.5rem;
    border: 1px solid #c0392b;
    border-radius: 6px;
    background: #fff;
    color: #c0392b;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.2s;
}

.btn-retry:hover {
    background: #fdf0ef;
}

@media (max-width: 768px) {
    .catalog-page {
        flex-direction: column;
    }

    .catalog-sidebar {
        flex: none;
        width: 100%;
    }
}

